namespace Api.EndPoint.Chat;

/// <summary>
/// Endpoint for creating a new channel chat conversation.
/// </summary>
public class CreateChannelEndPoint : ICarterModule
{
    /// <summary>
    /// Configures the route for channel conversation creation.
    /// </summary>
    /// <param name="app">The endpoint route builder.</param>
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapPost("/chat/channels", async (
            HttpContext context,
            [FromForm] string name,
            [FromForm] string handle,
            [FromForm] string? description,
            ISender sender,
            IUploadServiceApi uploadServiceApi,
            IOptions<PathOption> options,
            CancellationToken cancellationToken) =>
        {
            try
            {
                var form = await context.Request.ReadFormAsync(cancellationToken);
                var memberUserIds = ParseMemberUserIds(form);
                string? avatarUrl = null;

                var avatar = form.Files.GetFile("avatar");
                if (avatar is { Length: > 0 })
                {
                    var uploaded = await uploadServiceApi.UploadAsync(
                        options.Value.ChatFiles,
                        [avatar]);
                    avatarUrl = uploaded.FirstOrDefault()?.Name;
                }

                var res = await sender.Send(
                    new CreateChannelConversationCommand(
                        name,
                        handle,
                        description,
                        avatarUrl,
                        memberUserIds),
                    cancellationToken);

                if (res.IsSuccess)
                    return Results.Json(res.Value, statusCode: StatusCodes.Status201Created);

                if (res.Error!.ErrorType == ErrorType.Conflict)
                    return Results.Problem(res.Error.Description, statusCode: StatusCodes.Status409Conflict);

                return Results.Problem(res.Error.Description, statusCode: 400);
            }
            catch (Exception ex)
            {
                Log.Error(ex, "CreateChannelConversation");
                return Results.Problem("خطا در ایجاد کانال", statusCode: 400);
            }
        })
        .WithName("CreateChannelConversation")
        .WithTags("Chat")
        .Produces<ConversationDetailDto>(StatusCodes.Status201Created)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .ProducesProblem(StatusCodes.Status409Conflict)
        .WithSummary("Create channel conversation")
        .WithDescription("Creates a new channel with a unique handle, optional description, avatar, and initial members.")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization()
        .DisableAntiforgery();
    }

    private static List<int> ParseMemberUserIds(IFormCollection form)
    {
        var memberUserIds = new List<int>();

        if (!form.TryGetValue("memberUserIds", out var values))
            return memberUserIds;

        foreach (var value in values)
        {
            if (string.IsNullOrWhiteSpace(value))
                continue;

            foreach (var part in value.Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries))
            {
                if (int.TryParse(part, out var id) && !memberUserIds.Contains(id))
                    memberUserIds.Add(id);
            }
        }

        return memberUserIds;
    }
}

