namespace Application.DTOs.Chat;

/// <summary>
/// Payload for real-time system messages broadcast to a chat conversation.
/// </summary>
public class ChatSystemMessageDto
{
    /// <summary>Gets or sets the conversation identifier.</summary>
    public int ConversationId { get; set; }

    /// <summary>Gets or sets the system message text.</summary>
    public string Text { get; set; } = string.Empty;
}

using Application.DTOs.Chat;

namespace Application.Services.Interface;

/// <summary>
/// Pushes real-time chat events to connected SignalR clients.
/// </summary>
public interface IChatNotificationService
{
    /// <summary>Broadcasts a new message to conversation group members.</summary>
    Task SendMessageAsync(int conversationId, ChatMessageDto message, CancellationToken ct = default);

    /// <summary>Broadcasts that a message was edited.</summary>
