### a) `CreateOrGetPvConversationCommandHandler.cs`

```csharp
using Application.DTOs.Chat;
using Application.Features.App.Chat.Conversations.Queries.GetConversationDetail;

namespace Application.Features.App.Chat.Conversations.Commands.CreateOrGetPvConversation;

public class CreateOrGetPvConversationCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService,
    ISender sender)
    : IRequestHandler<CreateOrGetPvConversationCommand, Result<ConversationDetailDto>>
{
    public async Task<Result<ConversationDetailDto>> Handle(
        CreateOrGetPvConversationCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            if (currentUserId == request.TargetUserId)
                return ChatErrors.CannotChatWithYourself;

            var targetUserExists = await context.AppUsers
                .AsNoTracking()
                .AnyAsync(u => u.Id == request.TargetUserId && u.IsActive, cancellationToken);

            if (!targetUserExists)
                return ChatErrors.ConversationNotFound;

            var existingId = await context.ChatConversations
                .AsNoTracking()
                .Where(cv => cv.Type == ChatConversationType.PV
                    && cv.Participants.Any(p => p.UserId == currentUserId && p.LeftAt == null)
                    && cv.Participants.Any(p => p.UserId == request.TargetUserId && p.LeftAt == null))
                .Select(cv => cv.Id)
                .FirstOrDefaultAsync(cancellationToken);

            if (existingId > 0)
                return await sender.Send(new GetConversationDetailQuery(existingId), cancellationToken);

            var conversation = new ChatConversation
            {
                Type = ChatConversationType.PV,
                Name = string.Empty,
                CreatedByUserId = currentUserId
            };

            conversation.Participants.Add(new ChatParticipant
            {
                UserId = currentUserId,
                Role = ChatParticipantRole.Member,
                JoinedAt = DateTime.UtcNow
            });

            conversation.Participants.Add(new ChatParticipant
            {
                UserId = request.TargetUserId,
                Role = ChatParticipantRole.Member,
                JoinedAt = DateTime.UtcNow
            });

            context.ChatConversations.Add(conversation);
            await context.SaveChangesAsync(cancellationToken);

            return await sender.Send(new GetConversationDetailQuery(conversation.Id), cancellationToken);
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (CreateOrGetPvConversation): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}
```

### b) `GetConversationListQueryHandler.cs`

```csharp
using Application.DTOs.Chat;

namespace Application.Features.App.Chat.Conversations.Queries.GetConversationList;

public class GetConversationListQueryHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService)
    : IRequestHandler<GetConversationListQuery, Result<List<ConversationListItemDto>>>
{
    public async Task<Result<List<ConversationListItemDto>>> Handle(
        GetConversationListQuery request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var qBase = context.ChatParticipants
                .AsNoTracking()
                .Where(cp => cp.UserId == currentUserId && cp.LeftAt == null);

            if (!string.IsNullOrWhiteSpace(request.Search))
            {
                var search = request.Search.ToLower();
                qBase = qBase.Where(cp =>
                    EF.Functions.Like(cp.Conversation.Name.ToLower(), $"%{search}%")
                    || cp.Conversation.Messages.Any(m =>
                        m.Text != null && EF.Functions.Like(m.Text.ToLower(), $"%{search}%")));
            }

            var items = await qBase
                .Select(cp => new
                {
                    Id = cp.ConversationId,
                    cp.Conversation.Type,
                    cp.Conversation.Name,
                    cp.Conversation.AvatarUrl,
                    cp.IsMuted,
                    cp.LastReadMessageId,
                    LastMessage = cp.Conversation.Messages
                        .OrderByDescending(m => m.Id)
                        .Select(m => m.Text)
                        .FirstOrDefault(),
                    LastMessageAt = cp.Conversation.Messages
                        .OrderByDescending(m => m.Id)
                        .Select(m => (DateTime?)m.CreateDate)
                        .FirstOrDefault(),
                    UnreadCount = cp.Conversation.Messages
                        .Count(m => m.SenderId != currentUserId && m.Id > cp.LastReadMessageId)
                })
                .OrderByDescending(x => x.LastMessageAt ?? DateTime.MinValue)
                .ToListAsync(cancellationToken);

            var list = items.Select(x => new ConversationListItemDto
            {
                Id = x.Id,
                Type = x.Type.ToString(),
                Name = x.Name,
                AvatarUrl = x.AvatarUrl,
                LastMessage = x.LastMessage,
                LastMessageAt = x.LastMessageAt,
                UnreadCount = x.UnreadCount,
                IsMuted = x.IsMuted
            }).ToList();

            return Result<List<ConversationListItemDto>>.Success(list);
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (GetConversationList): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}
