    }
}

using Application.Services.Interface;

namespace Application.Features.App.Chat.Messages.Commands.MarkChatAsRead;

/// <summary>
/// Marks messages in a conversation as read for the current participant and pushes read-receipt events.
/// </summary>
/// <remarks>
/// <strong>Execution Flow:</strong>
/// <list type="number">
/// <item>Loads the current user's active participant row (tracked for update).</item>
/// <item>Validates the target message belongs to the conversation.</item>
/// <item>Advances <see cref="ChatParticipant.LastReadMessageId"/> monotonically.</item>
/// <item>For PV conversations, broadcasts <c>MessageRead</c> via SignalR.</item>
/// <item>Broadcasts <c>ConversationUpdated</c> with the reader's new unread count.</item>
/// </list>
/// </remarks>
public class MarkChatAsReadCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService,
    IChatNotificationService chatNotificationService)
    : IRequestHandler<MarkChatAsReadCommand, Result>
{
    /// <summary>
    /// Executes the mark-as-read command.
    /// </summary>
    /// <param name="request">The conversation id and last read message id.</param>
    /// <param name="cancellationToken">Token to observe for cancellation requests.</param>
    /// <returns><see cref="Result.Success()"/> when read state is updated or already up to date.</returns>
    public async Task<Result> Handle(
        MarkChatAsReadCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var participant = await context.ChatParticipants
                .FirstOrDefaultAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.UserId == currentUserId
                    && p.LeftAt == null,
                    cancellationToken);

            if (participant is null)
                return ChatErrors.NotAParticipant;

            var messageExists = await context.ChatMessages
                .AsNoTracking()
                .AnyAsync(m =>
                    m.Id == request.LastReadMessageId
                    && m.ConversationId == request.ConversationId,
                    cancellationToken);

            if (!messageExists)
                return ChatErrors.MessageNotFound;

            if (request.LastReadMessageId <= participant.LastReadMessageId)
                return Result.Success();

            participant.LastReadMessageId = request.LastReadMessageId;
            await context.SaveChangesAsync(cancellationToken);

            var conversationType = await context.ChatConversations
                .AsNoTracking()
                .Where(c => c.Id == request.ConversationId)
                .Select(c => c.Type)
                .FirstOrDefaultAsync(cancellationToken);

            if (conversationType == ChatConversationType.PV)
            {
                await chatNotificationService.MessageReadAsync(
                    request.ConversationId,
                    currentUserId,
                    request.LastReadMessageId,
                    cancellationToken);
            }

            int unreadCount = await context.ChatMessages
                .AsNoTracking()
                .CountAsync(m =>
                    m.ConversationId == request.ConversationId
                    && m.SenderId != currentUserId
                    && m.Id > participant.LastReadMessageId,
                    cancellationToken);

            await chatNotificationService.ConversationUpdatedAsync(
                request.ConversationId,
                unreadCount,
                cancellationToken);

            return Result.Success();
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (MarkChatAsRead): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

using Api.Constants;
using Application.Features.App.Chat.Messages.Commands.MarkChatAsRead;

namespace Api.EndPoint.Chat;

/// <summary>
/// Endpoint for marking chat messages as read in a conversation.
/// </summary>
public class MarkChatAsReadEndPoint : ICarterModule
{
    /// <summary>
    /// Configures the route for marking messages as read.
    /// </summary>
    /// <param name="app">The endpoint route builder.</param>
    public void AddRoutes(IEndpointRouteBuilder app)
    {
        app.MapPost("/chat/conversations/{conversationId:int}/read", async (
            int conversationId,
            MarkChatAsReadRequest body,
            ISender sender,
            CancellationToken cancellationToken) =>
        {
            var res = await sender.Send(
                new MarkChatAsReadCommand(conversationId, body.LastReadMessageId),
                cancellationToken);

            if (res.IsSuccess)
                return Results.Ok();
            return Results.Problem(res!.Error!.Description, statusCode: 400);
        })
        .WithName("MarkChatAsRead")
        .WithTags("Chat")
        .Produces(StatusCodes.Status200OK)
        .ProducesProblem(StatusCodes.Status400BadRequest)
        .WithSummary("Mark chat messages as read")
        .WithDescription("Updates the reader's last-read pointer and broadcasts read receipts for PV conversations.")
        .RequireRateLimiting(RateLimitConst.RateFix)
        .RequireAuthorization()
        .DisableAntiforgery();
    }
}

/// <summary>
/// Request body for marking messages as read.
/// </summary>
public record MarkChatAsReadRequest
{
    /// <summary>Gets or sets the highest message id the user has read.</summary>
    public int LastReadMessageId { get; set; }
}

