using Application.Services.Interface;

namespace Application.Features.App.Chat.Messages.Commands.EditChatMessage;

public class EditChatMessageCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService,
    IChatNotificationService chatNotificationService)
    : IRequestHandler<EditChatMessageCommand, Result>
{
    public async Task<Result> Handle(
        EditChatMessageCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var message = await context.ChatMessages
                .FirstOrDefaultAsync(m => m.Id == request.MessageId, cancellationToken);

            if (message is null)
                return ChatErrors.MessageNotFound;

            if (message.IsDeleted)
                return ChatErrors.MessageIsDeleted;

            if (message.SenderId != currentUserId)
                return ChatErrors.CannotEditMessage;

            message.Text = request.Text.Trim();
            message.IsEdited = true;
            message.EditedAt = DateTime.UtcNow;
            await context.SaveChangesAsync(cancellationToken);

            await chatNotificationService.MessageEditedAsync(
                message.ConversationId,
                message.Id,
                message.Text,
                message.EditedAt.Value,
                cancellationToken);

            return Result.Success();
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (EditChatMessage): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

