using Application.Services.Interface;

namespace Application.Features.App.Chat.Conversations.Commands.UpdateChannelInfo;

public class UpdateChannelInfoCommandHandler(
    IApplicationDbContext context,
    ICurrentUserService currentUserService,
    IChatNotificationService chatNotificationService)
    : IRequestHandler<UpdateChannelInfoCommand, Result>
{
    public async Task<Result> Handle(
        UpdateChannelInfoCommand request,
        CancellationToken cancellationToken)
    {
        try
        {
            int currentUserId = currentUserService.UserId();

            var adminParticipant = await context.ChatParticipants
                .AsNoTracking()
                .FirstOrDefaultAsync(p =>
                    p.ConversationId == request.ConversationId
                    && p.UserId == currentUserId
                    && p.LeftAt == null,
                    cancellationToken);

            if (adminParticipant is null)
                return ChatErrors.NotAParticipant;

            if (adminParticipant.Role != ChatParticipantRole.Admin)
                return ChatErrors.NotChannelAdmin;

            var conversationType = await context.ChatConversations
                .AsNoTracking()
                .Where(c => c.Id == request.ConversationId)
                .Select(c => c.Type)
                .FirstOrDefaultAsync(cancellationToken);

            if (conversationType != ChatConversationType.Channel)
                return ChatErrors.NotChannelAdmin;

            var conversation = await context.ChatConversations
                .FirstOrDefaultAsync(c => c.Id == request.ConversationId, cancellationToken);

            if (conversation is null)
                return ChatErrors.ConversationNotFound;

            bool nameChanged = false;

            if (!string.IsNullOrEmpty(request.Name))
            {
                conversation.Name = request.Name;
                nameChanged = true;
            }

            if (!string.IsNullOrEmpty(request.Description))
                conversation.Description = request.Description;

            if (!string.IsNullOrEmpty(request.AvatarUrl))
                conversation.AvatarUrl = request.AvatarUrl;

            await context.SaveChangesAsync(cancellationToken);

            if (nameChanged)
            {
                await chatNotificationService.SystemMessageAsync(
                    request.ConversationId,
                    $"نام کانال به {request.Name} تغییر یافت",
                    cancellationToken);
            }

            return Result.Success();
        }
        catch (Exception ex)
        {
            Log.Error($"CQRS (UpdateChannelInfo): {ex.Message}", ex);
            return Error.ServerError;
        }
    }
}

